const conversaciones = items[0].json.payload || [];
const INBOX_OBJETIVO = 7; // 👈 inbox nuevo

const encontrada = conversaciones.find(
  c => c.inbox_id === INBOX_OBJETIVO
);

if (!encontrada) {
  return [{
    json: {
      existe_conversacion: false
    }
  }];
}

return [{
  json: {
    existe_conversacion: true,
    conversation_id: encontrada.id
  }
}];

// Formatear input para WhatsApp
const wppData = $('une_data_wpp').first().json;

// Recuperar memoria de forma segura
const inputData = $input.first().json;
const memoria_contexto_array = inputData.ChatMemory || [];

// Obtener etapa actual de forma segura
const etapa_actual = memoria_contexto_array.length > 0 
  ? memoria_contexto_array[memoria_contexto_array.length - 1].etapa 
  : null;

// CONVERTIR ARRAY A TEXTO PLANO para que el AI Agent lo reconozca
let memoria_contexto = "";
if (memoria_contexto_array && memoria_contexto_array.length > 0) {
  memoria_contexto = memoria_contexto_array
    .map(item => `${item.created_at}: ${item.mensaje}`)
    .join('\n');
} else {
  memoria_contexto = ""; // Sin historial previo
}

// Extraer información del mensaje de WhatsApp
const message = wppData.messages[0]; // Primer mensaje del array
const contact = wppData.contacts[0]; // Primer contacto del array
const chatInput = wppData.mensajeUsuario;
const sessionId = message.from;

// Obtener nombre de usuario de forma segura
const tam_lista = memoria_contexto_array.length;
let userName = wppData.contacts[0]?.profile?.name || 'Cliente';

if (tam_lista > 0) {
  const aux = memoria_contexto_array[tam_lista - 1].nombre;   
  if (aux) {
    userName = aux;
  }
}

const celular = message.from;
const normalizedNumber = celular.replace(/^54/, "54"); 

// Formatear para el AI Agent
const formattedInput = {
  sessionId: sessionId,
  action: 'sendMessage',
  chatInput: chatInput,
  etapa_actual,
  userContext: {
    name: userName,
    userId: message.from,
    chatId: message.from,
    phoneNumberId: wppData.metadata.phone_number_id,
    displayPhoneNumber: wppData.metadata.display_phone_number,
    telefono_origen: normalizedNumber,
    messageId: message.id,
    timestamp: message.timestamp,
    platform: 'whatsapp',
    contexto_historial: memoria_contexto    
  }
};

return { json: formattedInput };

// Formatear input para WhatsApp
