const output = $input.first().json.output;
const contextData = output.context_data;

const provincia = contextData.provincia || "";

let zona_cobertura = "";
if (provincia === "Salta") {
  zona_cobertura = "Salta";
} else if (["Tucumán", "Santiago del Estero", "Jujuy"].includes(provincia)) {
  zona_cobertura = "Norte";
} else if (provincia) {
  zona_cobertura = "Fuera de zona";
}

const subestado = zona_cobertura === "Fuera de zona"
  ? "Baja probabilidad de compra"
  : "";

return {
  json: {
    ...output,
    context_data: {
      ...contextData,
      zona_cobertura,
      subestado
    }
  }
};

